import React from 'react'
import { Button, Space, Avatar } from 'antd';
import LabelTemplateIcon from '../../images/label_template_icon.svg'
import { containerConstantsService } from '../../utils/containerconstants/ContainerConstants';
import { TEMPLATE_MODAL_TYPE } from '../../utils/constants';

const containerConstants = containerConstantsService.getInstance();

const EmptyDataView = ({ setShowModalDialog }) => {
    return (
        <div id='template-empty-data-view'
            style={{ margin: '44px 0 0' }}
        >
            <Avatar src={LabelTemplateIcon} shape='square' />
            <h1>{containerConstants.formatString(containerConstants.TEMPLATE_NOT_FOUND)}</h1>
            <p>{containerConstants.formatString(containerConstants.TEMPLATE_NOT_FOUND_DESCRIPTION)}</p>
            <Space align='center'
                style={{ marginBottom: '36px' }} >
                <Button
                    style={{ color: '#FFFFFF' }}
                    type="primary"
                    onClick={() => setShowModalDialog({
                        visible: true,
                        title: containerConstants.formatString(containerConstants.CHOOSE_TEMPLATE),
                        modalType: TEMPLATE_MODAL_TYPE.CHOOSE_TEMPLATE
                    })}
                >
                    {containerConstants.formatString(containerConstants.CREATE_TEMPLATE)}
                </Button>
            </Space>
        </div>
    )
}

export default EmptyDataView
